    }
    
    private func generateKeyPair() {
        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: "com.example.cryptoWallet.private"
            ]
        ]
        
        SecKeyGeneratePair(attributes as CFDictionary, &publicKey, &privateKey)
    }
    
    func signTransaction(data: Data) -> Data? {
        guard let privateKey = privateKey else { return nil }
        var error: Unmanaged<CFError>?
        let signature = SecKeyCreateSignature(privateKey, .ecdsaSignatureMessageX962SHA256, data as CFData, &error)
        return signature as Data?
    }
    
    func sendTransaction(to address: String, amount: Double) {
        let transactionData = createTransactionData(to: address, amount: amount)
        guard let signedData = signTransaction(data: transactionData) else { return }
        broadcastTransaction(signedData: signedData)
    }
    
    private func createTransactionData(to address: String, amount: Double) -> Data {
        let transaction = ["to": address, "amount": amount] as [String : Any]
        return try! JSONSerialization.data(withJSONObject: transaction, options: [])
    }
    
    private func broadcastTransaction(signedData: Data) {
        let url = URL(string: "https://blockchain.example.com/sendTransaction")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = signedData
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Error broadcasting transaction: \(error)")
                return
            }
            print("Transaction broadcasted successfully")
        }
        task.resume()
    }
